// // Asynchronous reset functionality: when rst is high, q is set to HIGH; on rising edge of clk, q is updated based on d only if en is low
module top_module(
                     input      rst,
                     input      clk,
                     input      en,
                     input      d,
                     output reg q
                     );always @(posedge clk or posedge rst) begin
      if (rst)
        q <= 1'b0;
      else if (en)
        q <= d;
   end
endmodule
